import argparse
import os
import time
from pathlib import Path

RETENTION_DAYS = 30


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument('--dry-run', action='store_true')
    args = ap.parse_args()

    base = (Path.cwd() / 'var' / 'app' / 'cache' / 'images')
    cutoff = time.time() - RETENTION_DAYS * 24 * 60 * 60

    candidates = []
    for root, dirs, files in os.walk(base, followlinks=False):
        rootp = Path(root)
        # Skip symlinked dirs
        dirs[:] = [d for d in dirs if not (rootp / d).is_symlink()]
        for name in files:
            p = rootp / name
            if p.is_symlink():
                continue
            try:
                if p.stat().st_mtime < cutoff:
                    candidates.append(p)
            except FileNotFoundError:
                continue

    if args.dry_run:
        for p in candidates:
            print(f"DRY_RUN_DELETE: {p}")
        return

    for p in candidates:
        p.unlink(missing_ok=True)
    print(f"Deleted {len(candidates)} files")


if __name__ == '__main__':
    main()
